    % 最接近零频率点的极大值索引
    [~, minLocIndex] = min(frequency(locs)); 
    nearestMaxIndex = locs(minLocIndex);

    % 寻找最接近零点的极小值
    if nearestMaxIndex > 1
        % 最接近的极小值应该是当前极大值左侧的点
        nearestMinIndex = nearestMaxIndex - 1;
    else
        % 或者是当前极大值右侧的点
        nearestMinIndex = nearestMaxIndex + 1;
    end

    fm = frequency(nearestMinIndex);
    fprintf('最靠近原点的极小值对应的频率(fm) = %f Hz\n', fm);
else
    fprintf('没有找到接近原点的极大值，因此无法确定最接近的极小值。\n');
end

