ylabel('Magnitude');
title('Spectrum Analysis of the Rectangular Pulse Signal');
grid on;
axis tight; % 自动调整坐标轴的范围以显示所有数据
hold on;
if ~isempty(locs)
    plot(frequency(nearestMaxIndex), -pks(minLocIndex), 'ro'); % 极大值点
    plot(fm, magnitude(nearestMinIndex), 'r*'); % 最靠近原点的极小值点
end
hold off;
