% plot(frequency, magnitude);
% xlabel('Frequency (Hz)');
% ylabel('Magnitude');
% title('Spectrum Analysis of the Rectangular Pulse Signal.');
% grid on;
% axis([-5e5, 5e5, -0.01, 0.21]); 

% 计算归一化幅度的相反数，因为findpeaks函数寻找局部极大值
invMagnitude = -magnitude;

% 找到直流分量（DC）的索引
[~, dcIndex] = min(abs(frequency));

% 使用findpeaks寻找所有倒谱的局部极大值，即原谱的极小值
[pks, locs] = findpeaks(invMagnitude(dcIndex:end));
locs = locs + dcIndex - 1; % 调整索引以反映整个频谱

% 确保我们找到了至少一个极大值，并获取其中最小的一个（最接近DC的）
if ~isempty(locs)
    % 最接近零频率点的极大值索引
    [~, minLocIndex] = min(frequency(locs)); 
    nearestMaxIndex = locs(minLocIndex);

    % 寻找最接近零点的极小值
    if nearestMaxIndex > 1
        % 最接近的极小值应该是当前极大值左侧的点
        nearestMinIndex = nearestMaxIndex - 1;
    else
        % 或者是当前极大值右侧的点
        nearestMinIndex = nearestMaxIndex + 1;
    end

    fm = frequency(nearestMinIndex);
    fprintf('最靠近原点的极小值对应的频率(fm) = %f Hz\n', fm);
else
    fprintf('没有找到接近原点的极大值，因此无法确定最接近的极小值。\n');
end


% 绘制频谱图，标记最靠近原点的极小值
figure;
plot(frequency, magnitude);
xlabel('Frequency (Hz)');
ylabel('Magnitude');
title('Spectrum Analysis of the Rectangular Pulse Signal.');
grid on;
axis([-5e5, 5e5, 0, max(magnitude)]); % 设置合理的X轴范围
hold on;
if ~isempty(locs)
    plot(frequency(nearestMaxIndex), -pks(minLocIndex), 'ro'); % 极大值点
    plot(fm, magnitude(nearestMinIndex), 'r*'); % 最靠近原点的极小值点
end
hold off;

